const lead = $input.item.json;
const email = lead.email || lead.company_url || '';
let domain = '';

if (email.includes('@')) {
  domain = email.split('@')[1];
} else if (email.startsWith('http')) {
  try {
    domain = new URL(email).hostname.replace('www.', '');
  } catch (e) {
    domain = email;
  }
} else {
  domain = email;
}

const freeProviders = ['gmail.com', 'yahoo.com', 'hotmail.com', 'outlook.com', 'icloud.com'];
const isBusinessEmail = domain && !freeProviders.includes(domain.toLowerCase());

return { 
  ...lead, 
  extracted_domain: domain,
  is_business: isBusinessEmail
};

const originalLead = $("Extract Domain").item.json;
const clearbitData = $input.item.json;

let enriched = { ...originalLead };

if (Array.isArray(clearbitData) && clearbitData.length > 0) {
  const topMatch = clearbitData[0];
  enriched.company_name = enriched.company_name || topMatch.name;
  enriched.company_logo = topMatch.logo;
  enriched.company_domain = topMatch.domain;
  enriched.enrichment_source = 'clay_n8n';
  enriched.enriched_at = new Date().toISOString();
}

return enriched;

const lead = $("Merge Enrichment").item.json;
const aiData = $input.item.json;

return {
  ...lead,
  ai_research: aiData?.choices?.[0]?.message?.content || 'Research failed',
  status: 'enriched'
};
